#include<bits/stdc++.h>
using namespace std;

const int N = 7e3 + 5;
const double eps = 1e-8; 

int n, m;
double dis[N];
int cnt[N];
bool vis[N];

struct Edge {
    int v, w1, w2;
};
vector<Edge> e[N];

bool SPFA(double mid) {
    queue<int> q;
    for (int i = 1; i <= n; i++) {
        dis[i] = 0;
        cnt[i] = 0;
        vis[i] = true;
        q.push(i);
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        vis[u] = false;

        for (auto edge : e[u]) {
            int v = edge.v, w1 = edge.w1, w2 = edge.w2;
            double new_w = mid * w2 - w1;  

            if (dis[v] > dis[u] + new_w + eps) {  
                dis[v] = dis[u] + new_w;
                cnt[v] = cnt[u] + 1;
                if (cnt[v] >= n) return true;
                if (!vis[v]) {
                    vis[v] = true;
                    q.push(v);
                }
            }
        }
    }
    return false;
}

int main() {
    cin.tie(0)->sync_with_stdio(0);
    cin >> n >> m;
    for (int i = 1; i <= m; i++) {
        int u, v, w1, w2;
        cin >> u >> v >> w1 >> w2;
        e[u].push_back({v, w1, w2});
    }

    double l = 0, r = 1000;
    while (r - l > eps) {
        double mid = (l + r) / 2;
        if (SPFA(mid)) {
            l = mid;
        } else {
            r = mid;
        }
    }

    if (l < eps) {  
        printf("-1\n");
    } else {
        printf("%.1lf\n", l);
    }

    return 0;
}
